mapper.select:
SELECT 
FROM tb_mdm_option_code t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.option_family_code = #{optionFamilyCode}


    AND t.code = #{code}


    AND t.name = #{name}


    AND t.name_local = #{nameLocal}


    AND t.source = #{source}


    AND t.external_ref_id = #{externalRefId}


    AND t.external_version = #{externalVersion}


    AND t.last_sync_time = #{lastSyncTime}


    AND t.description = #{description}


    AND t.create_time = #{createTime}


    AND t.create_by = #{createBy}


    AND t.modify_time = #{modifyTime}


    AND t.modify_by = #{modifyBy}


    AND t.row_version = #{rowVersion}

ORDER BY t.code ASC

